mod = raa*bass*.5 - rab*(mid+treb)*.125;
mod = if(q1,bass*.5*(.5 + .5*sin(sp)) - (mid+treb)*.25*(.5 + .5*cos(sp)),mod);

toll = toll*(1-cop);
//toll = 15;


la = if((1-t3)*cop*equal(seg,1),tav,la);
lb = if((1-t3)*cop*equal(seg,2),tav,lb);
lc = if((1-t3)*cop*equal(seg,3),tav,lc);
ld = if((1-t3)*cop*equal(seg,4),tav,ld);
le = if((1-t3)*cop*equal(seg,5),tav,le);
lf = if((1-t3)*cop*equal(seg,6),tav,lf);
lg = if((1-t3)*cop*equal(seg,7),tav,lg);
li = if((1-t3)*cop*equal(seg,8),tav,li);
lj = if((1-t3)*cop*equal(seg,9),tav,lj);
lk = if((1-t3)*cop*equal(seg,10),tav,lk);

aa = if((1-t3)*cop*equal(seg,1),mod,aa);
ab = if((1-t3)*cop*equal(seg,2),mod,ab);
ac = if((1-t3)*cop*equal(seg,3),mod,ac);
ad = if((1-t3)*cop*equal(seg,4),mod,ad);
ae = if((1-t3)*cop*equal(seg,5),mod,ae);
af = if((1-t3)*cop*equal(seg,6),mod,af);
ag = if((1-t3)*cop*equal(seg,7),mod,ag);
ai = if((1-t3)*cop*equal(seg,8),mod,ai);
aj = if((1-t3)*cop*equal(seg,9),mod,aj);
ak = if((1-t3)*cop*equal(seg,10),mod,ak)*0;


lev = lev*above(sample,0); ud = ud*above(sample,0); rep = rep*above(sample,0); lev = if(ud,lev-1,lev+1); rep = (rep + equal(lev,0)); ud = if(equal(lev,0),0,if(equal(lev,10),1,ud));

mx = above(lev,0)*la*sin(aa) + above(lev,1)*lb*sin(ab) + above(lev,2)*lc*sin(ac) + above(lev,3)*ld*sin(ad);
my = above(lev,0)*la*cos(aa) + above(lev,1)*lb*cos(ab) + above(lev,2)*lc*cos(ac) + above(lev,3)*ld*cos(ad);
mx = mx + above(lev,4)*le*sin(ae) + above(lev,5)*lf*sin(af) + above(lev,6)*lg*sin(ag);
my = my + above(lev,4)*le*cos(ae) + above(lev,5)*lf*cos(af) + above(lev,6)*lg*cos(ag);
mx = mx + above(lev,7)*li*sin(ai) + above(lev,8)*lj*sin(aj);// + above(lev,9)*lk*sin(ak);
my = my + above(lev,7)*li*cos(ai) + above(lev,8)*lj*cos(aj) + above(lev,9)*lk*cos(ak);
mx = (1-2*equal(ud,1))*mx*(1-equal(lev,10));

my = min(my,.25);

// add branches via rotation
poi = q3;
modx = if(equal(lev,poi)*ud,mx,modx);
mody = if(equal(lev,poi)*ud,my,mody);
mang = (above(rep,7)*below(rep,14) - above(rep,15)*below(rep,22))*above(lev,poi);
modx = 0;
mx = mx - modx;
my = my - mody;
ox = mx*cos(mang) - my*sin(mang);
oy = mx*sin(mang) + my*cos(mang);
mx = ox + modx;
my = oy + mody;


mang = above(rep,1)*rep*1.0472;
ox = mx*cos(mang) - my*sin(mang);
oy = mx*sin(mang) + my*cos(mang);
mx = ox;
my = oy;


sz = .5;
x = mx*.75*sz + t1;
y = my*sz + t2;



